var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하아…… 하……","JPN":"はあ……はぁ……","ENG":"*Pant*","TWN":"呼呼……呼……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"마사키님…… 치후유……","JPN":"雅紀様……千冬……","ENG":"Mr. Katori... Chifuyu...","TWN":"雅紀……千冬……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이제 물러서야 합니다.","JPN":"退きましょう。","ENG":"We have to fall back.","TWN":"撤退吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"더 싸웠다간, 당주님마저 위험해집니다.","JPN":"これ以上戦えばご当主様の身も危うくなります。","ENG":"It could kill you if we go on.","TWN":"再打下去，連堂主都會有危險。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……아뇨.","JPN":"……いいえ。","ENG":"No.","TWN":"……不。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"버텨내기로 약속했습니다.","JPN":"耐えぬくと約束しました。","ENG":"I made a promise to stand my ground.","TWN":"我答應過要堅持下去。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"물러서지 않겠어요.","JPN":"退くわけにはいきません。","ENG":"I’m not falling back.","TWN":"我不會撤退的。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이걸 받아 주시겠습니까?","JPN":"これを受け取っていただけますか。","ENG":"Will you take this for me?","TWN":"請收下這個。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이건…… 가면?","JPN":"これは……お面？","ENG":"A mask?","TWN":"這是……面具？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"제 어미가 사라졌던 곳에서 찾아낸 물건입니다.","JPN":"私の母が消えた場所で見つけた物です。","ENG":"I found it on the ground where my mother had disappeared.","TWN":"這是在我母親消失的地方找到的。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"여전히 원망하고 있지만…… 차마 버리지는 못 하겠더군요.","JPN":"恨みは消えておりませんが……\\nどうしても捨てることはできませんでした。","ENG":"I am still resentful of her... but I just couldn’t throw it away.","TWN":"雖然我對她還有埋怨……但又不忍心扔掉。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사나에…….","JPN":"早苗様……","ENG":"Sanae...","TWN":"早苗……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"말씀드렸지요. 연합에 반드시 보탬이 되겠다고.","JPN":"申し上げたはずです。必ず連合の役に立ってみせますと。","ENG":"I told you I will help the Alliance.","TWN":"我說過，一定會幫助聯盟。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이것은 부디 당주님께서 맡아주십시오.","JPN":"これはどうか、ご当主様がお預かりください。","ENG":"Please take this for me, Lady.","TWN":"這個請堂主替我保管。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저는 제 몫을 다 하겠습니다.","JPN":"私は自分の役割を果たします。","ENG":"I will now do my part.","TWN":"我會盡自己的責任。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"다음은 너니?","JPN":"次は貴様か？","ENG":"So, it’s your turn now?","TWN":"下一個是你嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후후, 아직도 그런 표정을 지을 수 있다니.","JPN":"ふふ、まだそんな表情ができるとは。","ENG":"Hah hah, I like that look on your face.","TWN":"呵呵，竟然還能做出那種表情。"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너희는 추하게 발버둥치는 인간들보다 낫구나.","JPN":"貴様らは醜くもがく他の人間どもよりマシなようだな。","ENG":"You are better than those who disgracefully struggle for their lives.","TWN":"你們贏過那些狼狽掙扎的人呢～"},"stage":{"bg":"REEDS_FIELD","bgm":"THEMA_NANAHARA_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"비록 하찮은 재주다만, 네 놈을 상처입히기엔 충분할 거다.","JPN":"くだらぬ技だが、お前を傷つけるには十分だろう。","ENG":"Though I might be incompetent, this should be enough to hurt you.","TWN":"雖然我能力沒有很強，但要傷害你還是沒問題的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"크윽?!","JPN":"くうっ！！","ENG":"Argh?!","TWN":"呃呃？！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이 망할 것이!","JPN":"人間の分際で……！","ENG":"You filthy human!","TWN":"該死！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L36_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"치잇.","JPN":"チッ。","ENG":"Tsk.","TWN":"嗟。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"어리석은 것. 죽을 줄 알면서도, 저항 따윌 하다니.","JPN":"愚かな。死ぬと知りつつ抵抗するとは。","ENG":"Foolish human. You know your death is inevitable, yet you resist.","TWN":"蠢蛋，明知會死，還做無謂的反抗。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"힘만 원래대로, 아니, 머리 중 하나만 온전했어도 이까짓 공격이 통할 일따윈 없었을 텐데……","JPN":"力さえ戻れば、いや、頭の一つでも完全であれば\\nこの程度の攻撃が通じることなどなかったはず……","ENG":"If only my power was fully restored... no, only if I had only one of my heads intact, I would have been invincible...","TWN":"只有力量跟原本一樣，不，只有其中有一個顆頭是完整，剛剛的攻擊怎麼可能對我有效…"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치님! 괜찮으십니까?","JPN":"オロチ様！　ご無事でしょうか？","ENG":"Lord Orochi, are you alright?","TWN":"大蛇！您還好嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아아……","JPN":"ああ……","ENG":"Oh...","TWN":"啊啊……"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"그렇지. 네가 있었구나.","JPN":"そうか。貴様がいたな。","ENG":"Yes, I had you.","TWN":"沒錯，還有你！"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오로치님, 저에게도 힘을 나눠주십시오. 제가 오로치님을 도와 남은 것들을 처리하겠습니다.","JPN":"オロチ様、私にも力を分け与えてくださいませ。\\n私がオロチ様にお力添えをして、雑魚どもを処理します。","ENG":"Lord Orochi, please share some of your power with me, and I will smite them all with your blessing.","TWN":"大蛇，請分賜力量給我吧。我來幫大蛇除掉其餘的傢伙。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후훗, 나나하라 사요.","JPN":"ふふっ、七原小夜。","ENG":"Hah hah, Nanahara Sayo.","TWN":"呵呵，七原小夜。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L47_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"내가 왜 무녀로서의 재능도 없던 너 같은 방계에게 영생을 준 것인지 알고 있니?","JPN":"なぜ我が巫女としての才能もない、貴様のような傍系ごときに\\n永遠の命を与えたかわかるか？","ENG":"Do you know why I gave you eternal life, even when you’re from the collateral family and don’t have a single ounce of talent as a priestess?","TWN":"你身為旁系，而且明明是巫女，卻沒有任何才能，你知道我為何要賜你永生嗎？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"예?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"그야, 오로치님께 힘이 되어 드리기 위해서지요.","JPN":"それは、オロチ様の力になれるからではありませんか。","ENG":"Well, so that I may serve you?","TWN":"那是因為我要成為大蛇的幫手。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"명이 짧은 인간의 몸으로는 영원한 분이신 오로치님께 복종할 수 없을 테니까요.","JPN":"寿命の短い人間の体では、永遠を生きるオロチ様に\\n服従することはできないはずでしょうから。","ENG":"I won’t be able to serve the great eternal being if I’m a mortal.","TWN":"因爲以生命短暫的人類之身，無法服從永生的大蛇。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"아하핫.","JPN":"アハハッ。","ENG":"Ah hah hah!","TWN":"哈哈哈。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"앞은 맞고, 뒤는 틀렸네.","JPN":"半分は合っているが、半分は間違いだ。","ENG":"You’re only partially correct.","TWN":"前面是對的，但後面是錯的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"넌…… 내가 현세에 나왔을 때를 대비해 비축해둔,","JPN":"貴様は……我が現世に出た時に備えて備蓄しておいた。","ENG":"I gave you my power so that...","TWN":"你……只是為我出現在現世時而預備的。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"나의 힘일 뿐이란다.","JPN":"我の力にすぎぬ。","ENG":"I could use it when I wake up.","TWN":"你只是我的儲備力量。"},"stage":{"bg":"REEDS_FIELD","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAYO_NPC_NANAHARA_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"커흑……!","JPN":"がはっ……！","ENG":"Urgh!","TWN":"咳呃……！"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"오, 오로치님…… 어, 어째서 저를……","JPN":"オ、オロチ様……ど、どうして私を……","ENG":"L-Lord Orochi... Why... Why do you...","TWN":"大…大蛇……為什麼……"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"당신이 깨어나길 기다리면서…… 내가 어떤 짓들까지 해왔는데……","JPN":"あなた様が目覚めるのを待ちながら……\\n私がどれだけのことをしてきたか……","ENG":"After all these things that I’ve done for you... while I was waiting for you...","TWN":"我一直忠心地……等候您甦醒過來……"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"무슨 소릴 하는 거니? 사요?","JPN":"何を言っているのだ、小夜？","ENG":"What are you talking about, Sayo?","TWN":"你在說什麼？小夜？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"난 네가 날 위해 복종한다고 생각한 적이 없단다.","JPN":"我は貴様が我のために服従していると思ったことはない。","ENG":"I never thought you were serving me out of loyalty.","TWN":"我從來不認為你服從我。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"너도 내가 아니라, 내가 가진 권능에 복종했을 뿐이잖아?","JPN":"貴様も我ではなく、我が持っている権能に服従しただけだろう？","ENG":"You only obeyed my power, not me.","TWN":"你也不是服從我，而是服從我的能力吧？"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"내가 인간을 끔찍이 싫어한다는 걸 알면서도 너만은 예외일 거라고 생각하다니.","JPN":"我が人間を憎んでいることを知りながら、自分だけは例外だと思っていたとは。","ENG":"You know how I hate humans, and you thought I would make you an exception?","TWN":"你明知我很討厭人類，卻認爲只有你是例外。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"인간이란, 그렇게 오랜 세월을 살아도 여전히 어리석구나.","JPN":"人間というものは長い歳月を生きたとしても、相変らず愚かだな。","ENG":"You humans... You’re always so foolish, no matter how old you are.","TWN":"人類，經過那麼長的歲月，還是那麼愚蠢。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAYO_NPC_NANAHARA_NULL","text":{"KOREA":"이…… 이 빌어먹을 뱀년이……","JPN":"この……このろくでもない蛇ごときが……","ENG":"You... cursed snake...","TWN":"你……這該死的蛇女……"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"이제, 꿈에서 깰 시간이다.","JPN":"さあ、夢から覚める時だ。","ENG":"It’s time to wake up.","TWN":"現在該清醒囉。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"후후훗, 간만에 느껴보는 이 힘. 좋구나.","JPN":"ふふふっ、久しぶりに感じるこの力。よいぞ。","ENG":"Hah hah, it feels great to have some of my power restored.","TWN":"呵呵呵，好久沒感受到這股力量，真不錯。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"인간의 몸에 담아둔 것이라 보잘 것 없는 크기지만.","JPN":"人間の身に留めておいたせいで、取るに足らない大きさだが。","ENG":"It’s a pity that I couldn’t store much in that small vessel.","TWN":"裝在人類身體裡有點可惜。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"나머지는 천천히 채워 나가면 될 일이지.","JPN":"残りはゆっくり満たしていけばよい。","ENG":"Well, I’ll recover the rest of my power over time.","TWN":"剩下的慢慢填滿吧。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"OROCHI_JAPAN_NULL_NULL","text":{"KOREA":"자, 다시 한 번 해보자꾸나.","JPN":"さあ、もう一度やってみよう。","ENG":"Now, let’s try this again.","TWN":"來吧，再試一次。"},"stage":{"bg":"REEDS_FIELD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OROCHI_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};